        self.primes_set = set(self.primes)  # Initial set of primes
        self.primes_queue = deque(self.primes)  # Queue for primes

    def _is_prime(self, num):
        if num < 2:
            return False
        for prime in self.primes:
            if prime * prime > num:
                break
            if num % prime == 0:
                return False
        return True

    def _sieve(self, limit):
        sieve = [True] * (limit + 1)
        sieve[0] = sieve[1] = False
        for i, is_prime in enumerate(sieve):
            if is_prime:
                for n in range(i * i, limit + 1, i):
                    sieve[n] = False
        return [num for num, prime in enumerate(sieve) if prime]

